// BUILD DAR UPDATES — enrich the existing day's DAR row with verified box-score
// numbers from promoted Inbox rows. Gate: Record Lifecycle='Validated' AND
// Entity Type in {property_unit, workorder}. Match an EXISTING DAR by Property +
// DAR Date; if none exists, leave the row Validated (never create a DAR here).
//
// Bug 27: Notion getAll strips '%' from property names on READ — 'Occupied %' ->
// property_occupied, 'Lease %' -> property_lease. We read those flat keys but WRITE
// using the real property names ('Occupied %|number') downstream.
function __d(v){if(v==null)return '';if(typeof v==='string')return v.slice(0,10);if(typeof v==='object'){var s=v.start||(v.date&&v.date.start)||v.startDate||'';if(!s){var m=JSON.stringify(v).match(/\d{4}-\d{2}-\d{2}/);if(m)s=m[0];}return String(s).slice(0,10);}return String(v).slice(0,10);}
const inbox = $('Query Inbox Rows').all();
const dars = $('Query DAR Rows').all();

// property_code -> DAR Property select value (extend as properties are added)
const propMap = { 'eddy': 'The Eddy at Riverview Landing' };

// index existing DARs by 'PropertyName|YYYY-MM-DD'
const darIndex = {};
for (const d of dars) {
  const prop = String(d.json.property_property || '').trim();
  const date = __d(d.json.property_dar_date);
  if (prop && date) darIndex[prop + '|' + date] = d.json;
}

const wanted = new Set(['property_unit', 'workorder']);
const num = (v) => (v == null || v === '' ? null : Number(v));
const out = [];

for (const r of inbox) {
  const j = r.json;
  if (String(j.property_record_lifecycle || '') !== 'Validated') continue;
  if (!wanted.has(String(j.property_entity_type || ''))) continue;

  let payload = {};
  try { payload = JSON.parse(j.property_payload_json || '{}'); } catch (e) { payload = {}; }
  const measures = (payload && payload.measures) || {};

  const code = String(j.property_property_code || j.property_program || '').trim().toLowerCase();
  const propName = propMap[code] || String(j.property_program || '').trim();
  const date = __d(j.property_captured_at);
  const darRow = darIndex[propName + '|' + date];
  if (!darRow) continue; // no DAR for that property+date — leave Validated, do not create

  // measure value if provided, else keep the DAR's existing value (no clobber)
  const occ = measures.occupied_pct != null ? Number(measures.occupied_pct) : num(darRow.property_occupied);
  const lease = measures.leased_pct != null ? Number(measures.leased_pct) : num(darRow.property_lease);
  const pendWO = measures.workorders_overdue != null ? Number(measures.workorders_overdue) : num(darRow.property_pending_work_orders);

  out.push({ json: {
    inbox_page_id: j.id,
    dar_page_id: darRow.id,
    property: propName,
    dar_date: date,
    occupied_pct: occ,
    leased_pct: lease,
    pending_wo: pendWO,
    entity_type: String(j.property_entity_type || ''),
    entity_key: String(j.property_entity_key || ''),
    promoted_at: new Date().toISOString()
  }});
}

if (!out.length) return [{ json: { _empty: true, message: 'No Validated property_unit/workorder rows with a matching DAR to promote.' } }];
return out;
